import{_ as o,c as r,o as n,ae as s}from"./chunks/framework.B7Y1jjX-.js";const c=JSON.parse('{"title":"==第四题==","description":"","frontmatter":{},"headers":[],"relativePath":"notes/学习/学校竞赛、项目/数学建模/课程知识/论文框架.md","filePath":"notes/学习/学校竞赛、项目/数学建模/课程知识/论文框架.md"}'),e={name:"notes/学习/学校竞赛、项目/数学建模/课程知识/论文框架.md"};function l(a,t,g,i,h,d){return n(),r("div",null,[...t[0]||(t[0]=[s('<h1 id="第四题" tabindex="-1">==第四题== <a class="header-anchor" href="#第四题" aria-label="Permalink to &quot;==第四题==&quot;">​</a></h1><hr><p>下面把你这份“Q4：QC-Selective LightGBM + Conformal（改进版）”代码拆成可直接写进论文/报告的方法描述，并逐段解释为什么这样做。为便于对照，我保留了关键变量名（如 <code>z13</code>、<code>gest_week</code>、<code>rc_table</code> 等）。</p><h1 id="方法总览" tabindex="-1">方法总览 <a class="header-anchor" href="#方法总览" aria-label="Permalink to &quot;方法总览&quot;">​</a></h1><p>目标：以附件数据中女胎样本的非整倍体标注（13/18/21 染色体的“AB 列”）为判定结果，综合 X 染色体及 13/18/21 的 Z 值、GC 含量、读段及相关比例、BMI 等因素，给出女胎异常判定方法。检测有效孕周通常限定在 10–25 周，本方法在该窗口内建模并进行质量控制与可靠性保证。</p><p>方法管线包含四层：①字段规整与孕周解析 → ②质控门（QC gate） → ③成本敏感的 LightGBM 二分类器 + 概率校准 → ④分割式 Conformal 预测集（带拒判）与风险-覆盖分析。</p><hr><h2 id="_1-字段规整与孕周解析-robust-i-o" tabindex="-1">1. 字段规整与孕周解析（Robust I/O） <a class="header-anchor" href="#_1-字段规整与孕周解析-robust-i-o" aria-label="Permalink to &quot;1. 字段规整与孕周解析（Robust I/O）&quot;">​</a></h2><p><strong>做了什么：</strong></p><ul><li>通过模糊匹配函数 <code>find_col</code> 在原始表头中自动定位关键列：标签列（如“是否异常/非整倍体/AB/label”等）、Z 值（13/18/21/X）、测序质控字段（GC、比对率、唯一比对读段、重复率、过滤率）、母体特征（BMI、年龄）以及孕周列。</li><li>将孕周文本统一解析为浮点周数（如“12周+3天”“12w+3”→<code>12+3/7</code>），得到标准化的 <code>gest_week</code>。</li></ul><p><strong>为什么这样做：</strong> 竞赛附件的表头命名存在变体与中英文混排，模糊匹配能提升脚本的鲁棒性；孕周以“周+天”给出，统一成数值周数才能用于数值建模与筛选。附件对字段含义与判定依据有明确说明，本步骤即是把这些信息映射成可用数据结构。</p><hr><h2 id="_2-质控门-qc-gate" tabindex="-1">2. 质控门（QC gate） <a class="header-anchor" href="#_2-质控门-qc-gate" aria-label="Permalink to &quot;2. 质控门（QC gate）&quot;">​</a></h2><p><strong>做了什么：</strong></p><ul><li>仅保留 <code>gest_week ∈ [10, 25]</code> 的样本（<code>QC_WEEK_MIN, QC_WEEK_MAX</code>）。</li><li>对若干测序质量字段（如 GC、比对率、唯一比对读段、重复率、过滤率）做温和的分位裁剪筛选：保留各列 2%–98% 分位区间内的样本（<code>qclip_mask</code>），得到通过 QC 的数据子集 <code>df_qc</code> 与对应标签 <code>y_qc</code>。</li></ul><p><strong>为什么这样做：</strong></p><ul><li>10–25 周为题面常用的有效检测窗口，超出范围的样本不具可比性，会引入系统偏差。</li><li>测序类特征常含极端值（批次问题、运行异常等），温和分位筛选可在不依赖强分布假设的情况下去除异常样本，稳定后续模型。</li></ul><hr><h2 id="_3-特征装配与缺失处理" tabindex="-1">3. 特征装配与缺失处理 <a class="header-anchor" href="#_3-特征装配与缺失处理" aria-label="Permalink to &quot;3. 特征装配与缺失处理&quot;">​</a></h2><p><strong>做了什么：</strong></p><ul><li>采用“存在即用”的策略组装特征列表 <code>num_feats</code>：13/18/21/X 的 Z 值、X 浓度（若有）、整体/分染色体 GC、比对率、唯一比对读段、重复率、过滤率、BMI、年龄与 <code>gest_week</code>。</li><li>全部强制转为数值，并用列中位数填补缺失。</li></ul><p><strong>为什么这样做：</strong></p><ul><li>题面建议的因素均纳入，兼顾测序质量与母体特征；中位数填补在异质列上更稳健。附件指出 X、13/18/21 的 Z 值与多项质量指标是判定的重要依据，将其作为主特征符合业务先验。</li></ul><hr><h2 id="_4-数据分层切分-避免信息泄漏" tabindex="-1">4. 数据分层切分（避免信息泄漏） <a class="header-anchor" href="#_4-数据分层切分-避免信息泄漏" aria-label="Permalink to &quot;4. 数据分层切分（避免信息泄漏）&quot;">​</a></h2><p><strong>做了什么：</strong></p><ul><li>按标签分层把 QC 后数据切成 <strong>train / calib / test = 6/2/2</strong>；再把训练集切出 20% 做早停验证（<code>X_tr/X_val</code>），保证校准集 <code>calib</code> 不被提前使用。</li></ul><p><strong>为什么这样做：</strong></p><ul><li>我们需要<strong>独立的校准集</strong>用于概率校准与 Conformal 门限估计；把早停验证留在训练子集中可以避免对校准集“偷看”，确保后续覆盖率与误差评估的客观性。</li></ul><hr><h2 id="_5-成本敏感的-lightgbm-分类器" tabindex="-1">5. 成本敏感的 LightGBM 分类器 <a class="header-anchor" href="#_5-成本敏感的-lightgbm-分类器" aria-label="Permalink to &quot;5. 成本敏感的 LightGBM 分类器&quot;">​</a></h2><p><strong>做了什么：</strong></p><ul><li>以二分类 <code>LGBMClassifier</code> 为基础学习器，设置适中的树深与叶子数（<code>max_depth=6, num_leaves=31</code>）、子采样与列采样（0.8/0.8），并基于训练集中正负样本比设置 <code>scale_pos_weight</code>。先在 <code>X_tr/X_val</code> 上拟合以得到 <code>best_iteration_</code>，再用该迭代数在 <code>X_tr</code> 上重训。</li></ul><p><strong>为什么这样做：</strong></p><ul><li><strong>LightGBM</strong>在表格型、小至中等规模、特征间存在非线性/交互的任务上表现稳定，且原生支持缺失值与类别非线性切分，训练开销小、可解释性强（可产出特征重要性）。</li><li>女胎异常往往<strong>类不平衡</strong>，用 <code>scale_pos_weight</code> 显式调高正类权重以降低漏判风险，契合医疗场景“宁可多审慎、少漏诊”的代价结构。</li></ul><hr><h2 id="_6-概率校准-isotonic-regression" tabindex="-1">6. 概率校准（Isotonic Regression） <a class="header-anchor" href="#_6-概率校准-isotonic-regression" aria-label="Permalink to &quot;6. 概率校准（Isotonic Regression）&quot;">​</a></h2><p><strong>做了什么：</strong></p><ul><li>用<strong>各自独立的校准集 <code>calib</code><strong>上的原始预测概率 <code>p_cal_raw</code> 与真实标签 <code>y_cal</code> 训练</strong>各向单调</strong>的等分位回归（<code>IsotonicRegression</code>），得到校准映射 <code>iso</code>，并将其作用于校准集与测试集的概率，得到 <code>p_cal</code>、<code>p_test</code>。</li></ul><p><strong>为什么这样做：</strong></p><ul><li>树模型输出的原始分数常<strong>欠/过度校准</strong>。虽然 Conformal 方法<strong>不要求</strong>概率完美校准，但更接近真实的概率刻度通常能在相同覆盖率下<strong>降低选择性误差</strong>，也便于阈值制定与结果解释。</li></ul><hr><h2 id="_7-分割式-conformal-预测集-拒判机制" tabindex="-1">7. 分割式 Conformal 预测集 + 拒判机制 <a class="header-anchor" href="#_7-分割式-conformal-预测集-拒判机制" aria-label="Permalink to &quot;7. 分割式 Conformal 预测集 + 拒判机制&quot;">​</a></h2><p><strong>做了什么：</strong></p><ul><li>在校准集上定义<strong>非一致性分数</strong>：对于真实标签 $y$，分数为 $1-p_y$（阳性为 $1-p$，阴性为 $p$）；按给定 $\\alpha$ 取分位阈值 $q^*$。</li><li>对<strong>每个测试样本</strong>，构造其<strong>预测集</strong> $S\\subset{0,1}$：若类 0 的非一致性 $\\le q^*$ 则 0 ∈ S；若类 1 的非一致性 $\\le q^*$ 则 1 ∈ S。</li><li>若 $|S|=1$ 则输出该类；否则<strong>拒判</strong>（<code>-1</code>）。并统计<strong>覆盖率</strong>（非拒判比例）、<strong>选择性误差</strong>（在非拒判子集上的误差），绘制<strong>风险-覆盖（RC）曲线</strong>。</li></ul><p><strong>为什么这样做：</strong></p><ul><li><strong>分割式 Conformal</strong>在<strong>分布无关、有限样本</strong>前提下给出<strong>理论保证</strong>：在 i.i.d. 条件下，非拒判子集的<strong>误判率</strong>可由 $\\alpha$ 控制，覆盖率与风险形成可权衡的曲线。</li><li>医疗判定对<strong>可置信性</strong>要求高，引入<strong>拒判</strong>让模型在不确定时“少做决定”，将困难样本留给人工或二线检测，显著降低误诊风险。</li><li>代码提供固定 $\\alpha$（如 0.10）与<strong>自动选 $\\alpha$</strong> 两种模式：后者在满足最低覆盖率（例如 0.90）前提下<strong>最小化选择性误差</strong>，便于业务侧按“产能/时效/风险”确定运行点。</li></ul><hr><h2 id="_8-评估与可视化" tabindex="-1">8. 评估与可视化 <a class="header-anchor" href="#_8-评估与可视化" aria-label="Permalink to &quot;8. 评估与可视化&quot;">​</a></h2><p><strong>做了什么：</strong></p><ul><li>全量层面报告 <strong>ROC-AUC</strong>、<strong>PR-AUC</strong>；在非拒判子集报告<strong>选择性误差</strong>。</li><li>输出<strong>风险-覆盖表</strong> <code>rc_table</code> 与 <strong>RC 曲线</strong>，用于挑选运行点。</li><li>以 LightGBM 的 <code>feature_importances_</code> 绘制<strong>特征重要性 Top-20</strong>，用于规则核查与解释。</li></ul><p><strong>为什么这样做：</strong></p><ul><li>医疗稀疏阳性下，PR-AUC 更能反映实际检出能力；RC 曲线帮助管理者在“拒判成本”与“误诊成本”之间做透明权衡；特征重要性可发现“无正增益切分”等潜在数据/建模问题。</li></ul><hr><h2 id="_9-与题目要求的对应关系" tabindex="-1">9. 与题目要求的对应关系 <a class="header-anchor" href="#_9-与题目要求的对应关系" aria-label="Permalink to &quot;9. 与题目要求的对应关系&quot;">​</a></h2><ul><li><strong>判定目标</strong>：女胎异常以 13/18/21 的非整倍体为金标准（附件“AB 列”说明）。</li><li><strong>可用信息</strong>：纳入 X 与 13/18/21 的 Z 值、GC/读段/比对率等测序质量指标，以及 BMI、孕周等母体因素。</li><li><strong>时点约束</strong>：建模限定在 10–25 周的有效检测窗口，符合题面给出的实际检测区间。以上三点均与题目描述一致。</li></ul><hr><h2 id="_10-实施要点与可改进处" tabindex="-1">10. 实施要点与可改进处 <a class="header-anchor" href="#_10-实施要点与可改进处" aria-label="Permalink to &quot;10. 实施要点与可改进处&quot;">​</a></h2><ul><li><strong>类别不平衡</strong>：已用 <code>scale_pos_weight</code>；也可结合 focal loss 或样本重采样（注意与 Conformal 的独立性）。</li><li><strong>校准稳健性</strong>：等分位校准可做 K-折交叉版本以减轻过拟合。</li><li><strong>运行点选择</strong>：在 RC 曲线上，结合业务侧对“拒判比例”与“漏诊风险”的容忍度，选择 $\\alpha$ 或采用自动选取策略。</li><li><strong>可解释性</strong>：在临床发布层面保留特征重要性与若干典型样本的预测-校准-预测集全过程日志，便于审计。</li></ul><hr><h3 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to &quot;一句话总结&quot;">​</a></h3><p>这是一条“<strong>先保质控、再稳学习、用校准矫正概率、最后用 Conformal 管住可信度</strong>”的判定流水线：它尊重数据的检测窗口与质量特性，利用 LightGBM 处理表格非线性，借助等分位校准确保概率刻度，再用 Conformal 赋予<strong>可控的风险-覆盖权衡与拒判能力</strong>，使女胎异常判定既“能判准”，又“敢说不”。</p><h1 id="第三题" tabindex="-1">==第三题== <a class="header-anchor" href="#第三题" aria-label="Permalink to &quot;==第三题==&quot;">​</a></h1><hr><p>下面把你这份“<strong>男胎 Y 浓度达标时机优化（含 BMI 分层 + 离散时间生存 + 机会约束）</strong>”脚本，改写成可直接放进论文/报告的方法说明，并在每一步给出<strong>为什么这样做</strong>的理由。为便于核对，我保留关键术语（<code>earliest_week / person-period / hazard h(t) / F(t) / 机会约束 / CART 监督分箱</code> 等）。</p><hr><h1 id="研究目标与总体思路" tabindex="-1">研究目标与总体思路 <a class="header-anchor" href="#研究目标与总体思路" aria-label="Permalink to &quot;研究目标与总体思路&quot;">​</a></h1><p><strong>目标</strong>：在合法检测时窗（10–25 周）内，预测“孕周 tt”时<strong>累计达到可检阈值</strong>（默认 Y 浓度 ≥4%\\ge 4%）的概率曲线 F(t)F(t)，并在 <strong>BMI 分层</strong>的人群上，求出使“<strong>组内平均累计达标比例</strong> ≥ptarget\\ge p_{\\rm target}”（如 90%、95%）的<strong>最早孕周</strong> t*t^*，作为首检/复检的推荐时点。</p><p><strong>总体流程</strong>：<br> 数据规整 → 计算个体首次达标周 → <strong>BMI 的 CART 监督分箱</strong>（建人群层异质性）→ 构造 <strong>person-period</strong> 数据 → 训练<strong>离散时间生存森林</strong>近似区间危险度 h(t)h(t) 并做<strong>概率标定</strong> → 由 h(t)h(t) 累积得到 F(t)F(t) → <strong>机会约束</strong>求各 BMI 组的最优 t*t^* → <strong>灵敏度分析</strong>与可视化。</p><hr><h2 id="_1-数据规整与字段映射" tabindex="-1">1) 数据规整与字段映射 <a class="header-anchor" href="#_1-数据规整与字段映射" aria-label="Permalink to &quot;1) 数据规整与字段映射&quot;">​</a></h2><ul><li><p><strong>自动识别列名</strong>：用模糊匹配从原表中定位 ID、孕周、BMI、Y 浓度及可用协变量（年龄、身高、体重、GC、比对率、chr18_z）。</p></li><li><p><strong>孕周统一刻度</strong>：将“16w+2 / 16周+2天 / 16.5”等格式解析为<strong>浮点周数</strong>。</p></li><li><p><strong>Y 浓度统一刻度</strong>：若为百分数（&gt;1），统一换算为比例（0–1）。</p></li><li><p><strong>记录清洗</strong>：仅保留 <strong>Y 非空</strong> 且 <strong>孕周可解析</strong> 的男胎记录；同一孕周多测时取 <strong>Y 的最大值</strong>。</p></li></ul><p><strong>为什么</strong>：</p><ul><li><p>表头存在中英混用与别名，模糊匹配可提升鲁棒性；</p></li><li><p>时间与阈值比较需要一致的数值刻度；</p></li><li><p>对“是否可检测”类目标，“同周取最大”更贴近运营语义（达到即可）。</p></li></ul><hr><h2 id="_2-个体首次达标周-earliest-week" tabindex="-1">2) 个体首次达标周 <code>earliest_week</code> <a class="header-anchor" href="#_2-个体首次达标周-earliest-week" aria-label="Permalink to &quot;2) 个体首次达标周 `earliest_week`&quot;">​</a></h2><ul><li><p>设阈值 <strong>THRESH=0.04</strong>，对每位孕妇，找到 <strong>Y ≥\\ge 4%</strong> 的<strong>最早孕周</strong> <code>earliest_week</code>（未达标则为缺失）。</p></li><li><p>汇总得到逐孕妇表 <code>by_mother</code>（含 ID、BMI、<code>earliest_week</code> 及可用协变量）。</p></li></ul><p><strong>为什么</strong>：把“是否可检”转化为<strong>首次事件时间</strong>，为后续<strong>监督分箱</strong>和时间分布统计提供监督信号。</p><hr><h2 id="_3-bmi-的-cart-监督分箱-人群异质性" tabindex="-1">3) BMI 的 CART 监督分箱（人群异质性） <a class="header-anchor" href="#_3-bmi-的-cart-监督分箱-人群异质性" aria-label="Permalink to &quot;3) BMI 的 CART 监督分箱（人群异质性）&quot;">​</a></h2><ul><li>用 <strong>决策树回归（CART）</strong>，以 <strong>BMI</strong> 为自变量、以 <strong><code>earliest_week</code></strong> 为目标，学习 BMI 的<strong>最优切分点</strong>；限制<strong>最多 3 组</strong>（<code>MAX_LEAVES_BMI=3</code>）、<strong>每组事件样本 ≥ 30</strong>（<code>MIN_LEAF_BMI=30</code>），得到<strong>可解释的 BMI 组</strong>标签，并将分组回填至逐孕妇表与逐次检测表。</li></ul><p><strong>为什么选 CART 而非等距/等频</strong>：</p><ul><li><p>监督分箱<strong>面向目标</strong>（最小化组内方差、增大全局差异），可自动发现<strong>非线性阈值效应</strong>；</p></li><li><p>叶数与最小叶样本的约束抑制过拟合，使分组在样本有限时更稳定、可复现；</p></li><li><p>产出的是<strong>区间规则</strong>，便于临床沟通与执行。</p></li></ul><hr><h2 id="_4-person-period-数据构造-离散时间生存" tabindex="-1">4) person-period 数据构造（离散时间生存） <a class="header-anchor" href="#_4-person-period-数据构造-离散时间生存" aria-label="Permalink to &quot;4) person-period 数据构造（离散时间生存）&quot;">​</a></h2><ul><li><p>对每位孕妇，按孕周升序把相邻两次随访 [wk,wk+1)[w_k,w_{k+1}) 当作一个<strong>区间</strong>；</p></li><li><p>若“<strong>首次达标</strong>”落在右端点 wk+1w_{k+1}，则该区间 <strong>event=1</strong>，否则 <strong>event=0</strong>；未达标者所有区间 <strong>event=0</strong>（右删失思想）；</p></li><li><p>为每个区间构建特征：区间<strong>中点</strong> <code>interval_mid = (w_k+w_{k+1})/2</code> + 个体层协变量（BMI、年龄、体重、身高、GC、比对率、chr18_z 等）。</p></li></ul><p><strong>为什么</strong>：</p><ul><li><p>随访时间不等距、人数记录次数不同，用<strong>离散时间生存</strong>自然处理“首次达标”与<strong>右删失</strong>；</p></li><li><p><code>interval_mid</code> + 树模型即可逼近“达标风险随孕周变化”的形状。</p></li></ul><hr><h2 id="_5-区间危险度-h-t-h-t-学习与概率标定" tabindex="-1">5) 区间危险度 h(t)h(t) 学习与概率标定 <a class="header-anchor" href="#_5-区间危险度-h-t-h-t-学习与概率标定" aria-label="Permalink to &quot;5) 区间危险度 h(t)h(t) 学习与概率标定&quot;">​</a></h2><ul><li><p>以 <strong>随机森林分类器</strong>拟合区间层面的 Pr⁡(event=1∣features)\\Pr(\\text{event}=1\\mid \\text{features})，即近似<strong>危险度</strong> h(t)h(t)；</p></li><li><p>若样本/分组充足（样本≥50、ID 组≥2、正负例均存在），用 <strong>GroupShuffleSplit</strong>（按孕妇 ID 分组）做训练/验证切分，避免同一孕妇的区间泄漏到验证集；在验证集上用 <strong>isotonic</strong> 做<strong>概率标定</strong>，并报告 <strong>Brier 分</strong>与标定曲线；</p></li><li><p>若条件不满足，走<strong>降级路径</strong>（全量训练、不标定），保证流程可运行。</p></li></ul><p><strong>为什么</strong>：</p><ul><li><p>随机森林对表格数据稳健，能捕捉非线性/交互而不依赖参数假设；</p></li><li><p><strong>按 ID 分组切分</strong>能消除同一人的时间序列泄漏带来的乐观偏差；</p></li><li><p><strong>概率标定</strong>增强 h(t)h(t) 的可解释性，使后续由 h(t)h(t) 积累出的 F(t)F(t) 更可信。</p></li></ul><hr><h2 id="_6-由-h-t-h-t-得到累计达标曲线-f-t-f-t" tabindex="-1">6) 由 h(t)h(t) 得到累计达标曲线 F(t)F(t) <a class="header-anchor" href="#_6-由-h-t-h-t-得到累计达标曲线-f-t-f-t" aria-label="Permalink to &quot;6) 由 h(t)h(t) 得到累计达标曲线 F(t)F(t)&quot;">​</a></h2><ul><li><p>在网格 t∈[10,25]t\\in[10,25]（步长 0.1 周）上，对组内每位个体 ii 计算危险度序列 hi(t)h_i(t)；</p></li><li><p>逐点累乘得到<strong>生存函数</strong> Si(t)=∏k≤t(1−hi(tk))S_i(t)=\\prod_{k\\le t}(1-h_i(t_k))，再得<strong>累计达标概率</strong> Fi(t)=1−Si(t)F_i(t)=1-S_i(t)；</p></li><li><p>组内求平均，得到 Fgroup(t)=meani Fi(t)F_{\\rm group}(t)=\\text{mean}_i,F_i(t)。</p></li></ul><p><strong>为什么</strong>：这是离散生存框架下的标准关系，<strong>直观刻画</strong>“随孕周推进，达到可检标准的累计比例”。</p><hr><h2 id="_7-机会约束-各-bmi-组的-最优检测孕周-t-t" tabindex="-1">7) 机会约束：各 BMI 组的“最优检测孕周” t*t^* <a class="header-anchor" href="#_7-机会约束-各-bmi-组的-最优检测孕周-t-t" aria-label="Permalink to &quot;7) 机会约束：各 BMI 组的“最优检测孕周” t\\*t^\\*&quot;">​</a></h2><ul><li>给定目标覆盖 ptarget∈{0.90,0.95}p_{\\rm target}\\in{0.90,0.95}（分别对应首检/复检），在网格上寻找<strong>最早</strong>满足</li></ul><p>Fgroup(t) ≥ ptargetF_{\\rm group}(t)\\ \\ge\\ p_{\\rm target}</p><p>的 tt，记为 t*t^*。若在 10–25 周内<strong>达不到</strong>目标，则回报末端 Fgroup(25)F_{\\rm group}(25) 作为可达上限并提示策略调整。</p><p><strong>为什么</strong>：运营上追求“到此孕周时，<strong>至少</strong>有 ptargetp_{\\rm target} 的人已可检”。“取<strong>最早</strong>满足” 等价于在“<strong>时间越晚风险/成本越高</strong>”的设定下<strong>最小化风险</strong>。</p><hr><h2 id="_8-灵敏度分析与可视化" tabindex="-1">8) 灵敏度分析与可视化 <a class="header-anchor" href="#_8-灵敏度分析与可视化" aria-label="Permalink to &quot;8) 灵敏度分析与可视化&quot;">​</a></h2><ul><li><p><strong>灵敏度</strong>：对阈值（3.5%、4.0%、4.5%）和目标覆盖（0.90±0.02）重建 h(t)h(t) 与 t*t^*，检查推荐时点的<strong>稳健性</strong>（同步记录验证 Brier 分）。</p></li><li><p><strong>可视化</strong>：绘制各 BMI 组的 <strong>Fgroup(t)F_{\\rm group}(t) 曲线</strong>及目标横线；绘制“<strong>各组在不同目标下的 t*t^*</strong>”柱状图，便于直观比较。</p></li></ul><p><strong>为什么</strong>：阈值与 KPI 常受仪器、场景与管理要求影响，灵敏度分析量化“结论对参数设定的敏感度”，为上线口径提供依据。</p><hr><h2 id="_9-工程与鲁棒性设置" tabindex="-1">9) 工程与鲁棒性设置 <a class="header-anchor" href="#_9-工程与鲁棒性设置" aria-label="Permalink to &quot;9) 工程与鲁棒性设置&quot;">​</a></h2><ul><li><p>自动剔除<strong>整列缺失</strong>的特征；训练前对特征与 <code>event</code> 做<strong>丢缺</strong>；</p></li><li><p><strong>诊断打印</strong>（样本数、组数、正负例计数、特征清单）便于快速定位数据问题；</p></li><li><p><strong>降级路径</strong>保证在极端小样本/极端类分布时仍能产出结果（但概率解释性会弱化）。</p></li></ul><hr><h2 id="_10-可复现的关键超参-与实现一致" tabindex="-1">10) 可复现的关键超参（与实现一致） <a class="header-anchor" href="#_10-可复现的关键超参-与实现一致" aria-label="Permalink to &quot;10) 可复现的关键超参（与实现一致）&quot;">​</a></h2><ul><li><p>阈值 <code>THRESH=0.04</code>；合法时窗 <code>WIN_MIN=10, WIN_MAX=25</code>；网格步长 <code>GRID_STEP=0.1</code>；</p></li><li><p>目标覆盖 <code>P_TARGETS=[0.90,0.95]</code>；BMI 分箱 <code>MAX_LEAVES_BMI=3, MIN_LEAF_BMI=30</code>；</p></li><li><p>生存森林树数 <code>N_TREES=500</code>；随机种子 <code>RANDOM_STATE=2025</code>；</p></li><li><p>灵敏度：<code>THRESH_LIST=[0.035,0.04,0.045]</code>，<code>P_TARGET_DELTA=0.02</code>。</p></li></ul><hr><h3 id="一句话总结-1" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结-1" aria-label="Permalink to &quot;一句话总结&quot;">​</a></h3><p>本方法把“是否可检”建模为<strong>首次达标的离散时间事件</strong>，用<strong>随机森林</strong>学习“<strong>孕周推进下的达标危险度</strong>”，再转为<strong>累计达标曲线</strong> F(t)F(t)；在 <strong>BMI 监督分箱</strong>的人群上，通过<strong>机会约束</strong>选择“<strong>最早且覆盖达标</strong>”的孕周作为首检/复检推荐，并以<strong>概率标定与灵敏度分析</strong>保证<strong>可解释与稳健</strong>。</p><h1 id="第二题" tabindex="-1">==第二题== <a class="header-anchor" href="#第二题" aria-label="Permalink to &quot;==第二题==&quot;">​</a></h1><hr><p>下面把你这份“<strong>按 BMI 监督分箱→给出首检/复检推荐孕周</strong>”脚本，改写成可直接写进论文/报告的方法描述，并逐段解释“<strong>为什么这样做</strong>”。为便于对照，我保留关键名词（如 <em>earliest_week</em>、<em>CART 分箱</em>、<em>p90/p95</em> 等）。</p><h1 id="方法目的" tabindex="-1">方法目的 <a class="header-anchor" href="#方法目的" aria-label="Permalink to &quot;方法目的&quot;">​</a></h1><p>在男胎样本中，利用随访（不同孕周）的 <strong>Y 染色体浓度</strong> 记录，确定“<strong>首次达到可用阈值</strong>”（默认 4%）的 <strong>最早孕周</strong> <em>earliest_week</em>。再以 <em>earliest_week</em> 为监督信号，对 <strong>BMI</strong> 做监督式分箱，得到可解释的人群分层；最后在各 BMI 组内给出 <strong>首检</strong>（p90）与 <strong>复检</strong>（p95）推荐孕周作为运营建议。</p><hr><h1 id="数据规整与变量统一" tabindex="-1">数据规整与变量统一 <a class="header-anchor" href="#数据规整与变量统一" aria-label="Permalink to &quot;数据规整与变量统一&quot;">​</a></h1><ol><li><strong>字段自动定位与孕周解析</strong></li></ol><ul><li>通过模糊匹配自动找到 ID、孕周、BMI、Y 浓度等列。</li><li>将 “16w+2 / 16周+2天 / 16.5” 统一解析为<strong>浮点孕周</strong>。</li></ul><p><strong>为什么</strong>：原始表头常有中英混排与别名，模糊匹配可提升鲁棒性；统一孕周刻度是时间分析的前提。</p><ol start="2"><li><strong>Y 浓度刻度统一与样本筛选</strong></li></ol><ul><li>若 Y 值以百分数给出（&gt;1），统一换算为<strong>比例制</strong>（0–1）。</li><li>仅保留 <strong>Y 非空</strong> 且 <strong>孕周可解析</strong> 的男胎记录；对同一孕周多次测量，取 <strong>Y 的最大值</strong>（与检测“可用性”目标一致）。</li></ul><p><strong>为什么</strong>：阈值判断基于“是否达到可用标准”，取最大值更符合“达到即可”的运营语义；统一刻度避免阈值歧义。</p><hr><h1 id="指标定义-首次达标孕周" tabindex="-1">指标定义：首次达标孕周 <a class="header-anchor" href="#指标定义-首次达标孕周" aria-label="Permalink to &quot;指标定义：首次达标孕周&quot;">​</a></h1><ul><li>设阈值 <strong>THRESH = 0.04（4%）</strong>。对每位孕妇的纵向记录，计算 <strong>首次满足 Y ≥ 4%</strong> 的孕周，记为 <em>earliest_week</em>（未达标记 NaN）。</li><li>汇总成逐孕妇表 <em>by_mother</em>：包含（ID, BMI, earliest_week）。</li></ul><p><strong>为什么</strong>：把“是否可检测”转化为<strong>首次事件时间</strong>，这是后续做监督分箱与给出时间分位数推荐的基础。</p><hr><h1 id="监督式-bmi-分箱-cart-回归" tabindex="-1">监督式 BMI 分箱（CART 回归） <a class="header-anchor" href="#监督式-bmi-分箱-cart-回归" aria-label="Permalink to &quot;监督式 BMI 分箱（CART 回归）&quot;">​</a></h1><ul><li>使用 <strong>决策树回归（CART）</strong>，以 <strong>BMI</strong> 为自变量、以 <strong>earliest_week</strong> 为目标，学习 <strong>BMI 的最佳切分点</strong>。</li><li>约束：<strong>最多 4 组</strong>（<code>MAX_LEAVES=4</code>）与 <strong>每组≥30 人</strong>（<code>MIN_LEAF=30</code>），防止过拟合与不稳定小样本。</li><li>从树结构提取切分阈值，生成区间边界（-∞, cut1, cut2, …, +∞），据此给出 <strong>BMI_group_CART</strong> 标签。</li></ul><p><strong>为什么选择 CART 而不是等频/等距分箱</strong>：</p><ul><li>监督分箱让切分点服务于“<strong>尽可能解释 earliest_week 的差异</strong>”，能捕捉 <strong>非线性</strong> 与 <strong>阈值效应</strong>；</li><li>通过“最大叶数 + 最小叶样本”抑制过拟合，并提升统计稳定性与可复现性；</li><li>输出为<strong>区间规则</strong>，便于临床与运营沟通（“BMI 在 [x, y) 这组，建议…周首检”）。</li></ul><hr><h1 id="切分点-圆整-与可解释性增强" tabindex="-1">切分点“圆整”与可解释性增强 <a class="header-anchor" href="#切分点-圆整-与可解释性增强" aria-label="Permalink to &quot;切分点“圆整”与可解释性增强&quot;">​</a></h1><ul><li>将模型学得的切分点“<strong>圆整到 0.5</strong>”（<code>ROUND_STEP=0.5</code>），保证区间<strong>严格递增</strong>，避免圆整后重叠；用圆整后的边界重算分组（得到 <em>BMI_group_CART_round</em>）。</li></ul><p><strong>为什么</strong>：临床/一线更偏好 <strong>简单、整齐</strong> 的规则边界（如 23.5、27.0 周），圆整能减少“边界抖动”对推荐的影响，并提升跨批次使用时的稳健性与沟通成本友好度。</p><hr><h1 id="组内时间分位统计与推荐时点" tabindex="-1">组内时间分位统计与推荐时点 <a class="header-anchor" href="#组内时间分位统计与推荐时点" aria-label="Permalink to &quot;组内时间分位统计与推荐时点&quot;">​</a></h1><ul><li>对“<strong>有事件</strong>”（已达标）的个体，在每个 BMI 组内对 <em>earliest_week</em> 计算：样本数、均值/中位数、<strong>p90</strong> 与 <strong>p95</strong>、最小/最大。</li><li>在报告中将 <strong>p90</strong> 解释为“<strong>首检</strong> 推荐孕周”，<strong>p95</strong> 解释为“<strong>复检</strong> 推荐孕周”。</li></ul><p><strong>为什么用分位数而非均值</strong>：</p><ul><li>首检/复检决策追求“<strong>覆盖一定比例人群在此时点前已达标</strong>”的把握度，分位数（p90/p95）与运营 KPI（覆盖率/命中率）天然对齐；</li><li>相比均值，分位数对<strong>长尾与异常值不敏感</strong>，使推荐更稳健。</li></ul><hr><h1 id="对未达标者与全体的处理" tabindex="-1">对未达标者与全体的处理 <a class="header-anchor" href="#对未达标者与全体的处理" aria-label="Permalink to &quot;对未达标者与全体的处理&quot;">​</a></h1><ul><li>监督分箱仅用<strong>有事件样本</strong>学习阈值（能有效利用“何时达标”的信息）；</li><li>但<strong>最终分组</strong>也会覆盖<strong>全体个体</strong>（含未达标者），以便完整输出群体分层与后续扩展分析（如人群结构、资源配置）。</li></ul><p><strong>为什么</strong>：学习阶段需要“有事件”才能学习“时间差异”；而应用阶段需要让分组覆盖全部人群，才能在运营侧落地（排期、容量估算等）。</p><hr><h1 id="关键超参与默认值-与实现一致" tabindex="-1">关键超参与默认值（与实现一致） <a class="header-anchor" href="#关键超参与默认值-与实现一致" aria-label="Permalink to &quot;关键超参与默认值（与实现一致）&quot;">​</a></h1><ul><li><code>THRESH=0.04</code>：达标阈值（可按仪器/方案调整）。</li><li><code>MAX_LEAVES=4, MIN_LEAF=30</code>：限制树复杂度与每组下限，保证稳定性。</li><li><code>ROUND_STEP=0.5</code>：切分点圆整粒度（可设为 1.0 以进一步简化）。</li></ul><hr><h1 id="结果呈现与落地方式" tabindex="-1">结果呈现与落地方式 <a class="header-anchor" href="#结果呈现与落地方式" aria-label="Permalink to &quot;结果呈现与落地方式&quot;">​</a></h1><ul><li><strong>输出 1</strong>：BMI 分组的（圆整后）区间与样本量。</li><li><strong>输出 2</strong>：各 BMI 组的 <em>earliest_week</em> 统计表，重点报告 <strong>p90（首检）/p95（复检）</strong>。</li><li><strong>解读</strong>：例如，“BMI∈[x, y) 组，建议在 <strong>p90 周</strong>安排首检；若未达标，在 <strong>p95 周</strong>安排复检”。</li></ul><hr><h1 id="方法优点与边界" tabindex="-1">方法优点与边界 <a class="header-anchor" href="#方法优点与边界" aria-label="Permalink to &quot;方法优点与边界&quot;">​</a></h1><p><strong>优点</strong></p><ul><li>端到端：从原始随访 → 达标时点 → 监督分箱 → 推荐时点；</li><li>规则清晰：输出为“BMI 区间 + 推荐孕周（p90/p95）”，便于临床沟通；</li><li>稳健可复现：叶数/叶大小约束 + 圆整边界，减小偶然性波动。</li></ul><p><strong>边界与改进</strong></p><ul><li>若“有事件”样本太少（脚本中阈值 ❤️ 人直接报错），分箱与分位估计都不稳定；可并组或放宽 MIN_LEAF。</li><li><em>earliest_week</em> 基于单一阈值（4%），可做 <strong>灵敏度分析</strong>（例如 3.5%、4.5%）检查推荐时点的稳健性。</li><li>分箱只用 BMI，一般可与年龄/IVF/测序质量等变量<strong>联合分层</strong>，但需注意每组样本量充足。</li><li>若希望从“何时达标”的<strong>全时间过程</strong>给出覆盖-时间曲线和机会约束最优时点，可进一步采用<strong>离散时间生存建模</strong>（你在 Q2/Q4 中已实现）。</li></ul><hr><p><strong>一句话总结</strong> 本方法把“达到可检标准”转成“<strong>首次达标时间</strong>”，用 <strong>CART</strong> 在 <strong>BMI</strong> 上学习能解释时间差异的<strong>最优切分点</strong>，再以 <strong>p90/p95</strong> 给出各 BMI 组的<strong>首检/复检推荐孕周</strong>，实现“<strong>可解释的人群分层 + 可执行的时间策略</strong>”。</p>',165)])])}const u=o(e,[["render",l]]);export{c as __pageData,u as default};
